var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"으음…….","JPN":"うーん……","ENG":"Mm...","TWN":"嗯……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L3_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"이상하군. 분명 여기 있어야 할 텐데…….","JPN":"おかしいな。確かにここにあるはずだが……","ENG":"I don't get it. They have to have been here...","TWN":"奇怪，怎麼不在這裡……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"흠흐흠~♪ 얼른 빨래 하고 축구 보러 가야지~♪","JPN":"フンフフ～ン♪　早く洗濯して、サッカー観に行こうっと～♪","ENG":"La, la, la. ♪ Let's finish doing laundry and go watch football! ♪","TWN":"哼哼哼～♪ 趕快洗完衣服來去看足球～♪"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"어라? 세탁실에 무슨 일이야, 단장?","JPN":"あれ、団長？　洗濯室には何の用？","ENG":"Err? Captain? What are you doing in the laundry room?","TWN":"嗯？團長，你在洗衣間裡幹嘛？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"리, 리브 경? 설마 날 미행한 건가?","JPN":"り、リブ卿？　まさか後をつけていたのか？","ENG":"D-Dame Liv! Oh no, did you follow me?","TWN":"莉…莉芙卿？你該不會是跟蹤我吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"헤헤, 그럴 리가. 훈련 받고 났더니 운동복이 흙투성이가 됐거든.","JPN":"えへへ、まさか。　訓練してたら服が泥だらけになっちゃって。","ENG":"Heh heh. No way. My tracksuit got all muddy after training.","TWN":"嘿嘿，怎麼可能～是因為訓練完後，運動服整個髒兮兮的。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L11_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"부단장은 하루가 다르게 더 엄격해지는 거 같다니까.","JPN":"副団長って日に日に厳しくなってる気がするんだよね。","ENG":"The Deputy is becoming sterner by the day.","TWN":"還不是因為副團長一天比一天更嚴格！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L12_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"오늘은 공룡 운동복 입고 훈련 나왔다고 기강이 해이해졌다면서 구박하는 거 있지?","JPN":"今日は恐竜のジャージで訓練に出たら、たるんでるって怒られたの。","ENG":"I came to training with a dinosaur tracksuit today, and she was so hard on me, saying that discipline got lax.","TWN":"因為我今天穿著恐龍運動服去訓練，她就說我目無法紀，然後折磨我！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"공룡……?","JPN":"恐竜……？","ENG":"Dinosaur...?","TWN":"恐龍……？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"응. 심지어 그냥 공룡도 아니고 메카 티라노사우르스였다구.","JPN":"うん、それもメカ・ティラノサウルス！","ENG":"Yes. It wasn't just an ordinary dinosaur, either. It was a Mech T-Rex.","TWN":"對啊！而且它可不普通的恐龍，是暴龍欸！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스랑 한솔이도 귀엽다고 칭찬해 줬어!","JPN":"アリウスとイチロウもかわいいって褒めてくれたんだ。","ENG":"Arius and Hansol told me that it was cute.","TWN":"埃里奧斯和楊瀚也都說很可愛的！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으으……. 부단장이 훈련 중에 빵 터지는 모습을 보고 싶어서 잔뜩 기합 넣었는데.","JPN":"ううっ……訓練中に副団長が吹き出すところが見たくて、気合入れて用意したのに。","ENG":"Gah! I wore it to make the Deputy crack up during our training.","TWN":"哼……我為了要看副團長爆笑的表情，費了多大的力氣啊！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"크흠. 그런 복장은 훈련 중에 움직이기 불편해서 지적한 것 아니겠나?","JPN":"コホン……そんな服装は動きづらいから指摘したんじゃないのか？","ENG":"Hm... She was probably unhappy with you because such clothes can hinder your movement during training.","TWN":"咳咳，會不會是因為穿那種衣服不方便訓練，副團長才責備你的？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L18_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"단순히 아이들 잠옷처럼 귀엽게 생겼다고 꾸짖지는 않았을 거다.","JPN":"単に、子どものパジャマのような見た目だからという理由で怒ったわけではないだろう。","ENG":"She couldn't have punished you because your clothes looked like children's pajamas.","TWN":"應該不至於因為衣服長得跟睡衣一樣可愛就罵人吧？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L19_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"절대 아니야! 부단장이 눈을 이렇게 사납게 뜨고 그랬는걸?","JPN":"それは絶対違う！　副団長、こんな感じできつく睨んで言ったんだよ！","ENG":"Yes, she did! The Deputy glared at me and said,","TWN":"才不是咧！副團長的眼神這麼兇狠欸？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L22_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"<color=#ffd34c>평기사 분들도 보시는데 무슨 그런 유치한 복장을! 조디악 나이츠의 이름에 먹칠을 할 셈입니까?</color>","JPN":"<color=#ffd34c>平騎士の皆さんも見ているのにそんな幼稚な服装で来るとは！　ゾディアックナイツの名に泥を塗るつもりですか！</color>","ENG":"<color=#ffd34c>How can you show up in such childish attire before the knight bachelors? Are you trying to embarrass the Zodiac Knights?</color>","TWN":"<color=#ffd34c>平民騎士也都在看，你穿這是什麼幼稚的服裝！你是想害十二宮騎士團的名譽掃地嗎？</color>"},"stage":{"bg":"FALL_PARK","bgm":"CUTSCENE_TALK_01","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"으, 누가 전갈 아니랄까 봐.","JPN":"ううっ、やっぱりサソリは怖い。","ENG":"Hmpf, that scorpion.","TWN":"哼，怕人家不知道她是天蠍嗎！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"공룡도 안 되는 건가……? 그렇다면 나는 어떻게 해야……?","JPN":"恐竜も駄目なのか……？　それなら私はどうすれば……？","ENG":"So, she doesn't like dinosaurs, either. Then... what do I do...?","TWN":"恐龍也不行嗎……？那我該怎麼……？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L27_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"그런데 단장, 아까 봤는데 여기서 뭐 찾고 있었어?","JPN":"ところで団長はここで何か探してるの？","ENG":"By the way, Captain, are you looking for something here?","TWN":"不過團長，我剛有看到，你是在找什麼東西嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아, 그건…….","JPN":"あっ、それは……","ENG":"Ah, that's...","TWN":"喔，那個……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L29_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"앗? 설마 애인한테만 보여 주려고 산 비장의 속옷?","JPN":"ハッ！　まさか、恋人にだけ見せるつもりで買った勝負下着とか？","ENG":"Ooo, are you looking for some lacy underwear, something to buy for your lover?","TWN":"難道？是只能給親密愛人看的戰袍嗎？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L30_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그런 부끄러운 걸 공공 시설에 두는 사람이 어디 있나!!","JPN":"そんな恥ずかしいもの、共用施設に置くやつがいるか！","ENG":"Who leaves such embarrassing stuff in public facilities?","TWN":"誰會把那種害羞的東西放在公共場所啦！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"단장으로서 단원들이 사용하는 세탁실의 청결 상태를 확인하러 왔을 뿐이다. 다른 뜻은 없었어.","JPN":"団長として、団員たちが使っている洗濯室の様子を確認しに来ただけだ。","ENG":"As captain, I came here to check the cleanliness of the laundry room for my members. Nothing else.","TWN":"身為團長，我只是來確認團員們使用的洗衣間乾不乾淨，如此而已。"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그, 그러면 세탁에 열중하도록! 리브 경!","JPN":"せ、洗濯を頑張りなさい、リブ卿！　では！","ENG":"N-now, keep up your good work doing your laundry, Dame Liv!","TWN":"那…你就認真洗衣服吧，莉芙卿！"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"LIV_ZODIAC_NULL_NULL","text":{"KOREA":"지, 진짠가? 엄청 당황한 것 같은데?","JPN":"ほ、本当かな？　すごく焦ってたけど。","ENG":"Was I wrong? But then, why did she look so flustered?","TWN":"是嗎？明明看起來一副很驚慌的樣子？"},"stage":{"bg":"OFFICE_LOCKERROOM","bgm":"CUTSCENE_TALK_01","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LIV_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"큰일이군. 부단장의 기준으로는 공룡 잠옷도 실격인가.","JPN":"参ったな。副団長の基準だと、恐竜のパジャマもダメだとは。","ENG":"This is not good. To the Deputy, even dinosaur pajamas are disgraceful.","TWN":"糟糕，照副團長的標準，恐龍睡衣也不及格嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"너무 안일하게 생각했어. 세탁이 끝나는 대로 회수했어야 했는데…….","JPN":"甘かった……洗濯が終わり次第、回収すべきだったのに。","ENG":"I was careless. I should have retrieved them as soon as they were washed...","TWN":"我太大意了，應該一洗完就收起來的……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"부단장에게 발각되면 위험하다. 알렉산더는 명분이 있었기에 조용히 넘어갔지만…….","JPN":"副団長に見つかったら危ない。アレクサンダーの件は口実があったから目を瞑ってもらえたが……","ENG":"I can't let the Deputy see them. She tolerated Alexander because there was a valid reason, but now...","TWN":"萬一被副團長發現會有危險。上次亞歷山大是因為有充分的理由，她才沒說話的……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"단장의 유약한 모습은, 자칫 기사단의 사기에 악영향을 끼칠 수도 있어.","JPN":"団長が弱い姿を見せては、騎士団の士気に悪影響が出る可能性もある。","ENG":"As captain, I can't be seen as weak. That can demoralize the others.","TWN":"團長如果有任何柔弱的樣子，不謹慎點恐怕會影響騎士團的士氣。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 돌이켜 보면……. 충동적으로 구입한 것이 잘못일지도 모르겠군.","JPN":"しかし……あれを衝動買いしたのは、間違いだったかもしれない。","ENG":"In retrospect, perhaps I shouldn't have made that impulsive purchase in the first place.","TWN":"現在回想起來……當時真不應該衝動消費的。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"자, 자! 돈 주고도 못 살 희귀 굿즈들이 한가득! 둘러보고 가세요!","JPN":"さあさあ！　寄ってらっしゃい見てらっしゃい！　なかなか買えないレアグッズが盛りだくさんですよ！","ENG":"Come on, come on! Come take a look at this rare merchandise that you can't get anywhere else!","TWN":"來喔來喔！全都是用錢也買不到的寶貝喔！來看看喔～"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"히로세 씨……. 희귀 굿즈가 아니라 문 닫은 회사 건물에서 주워 온 잡동사니들이잖아요.","JPN":"廣瀬さん……これはレアグッズじゃなくて、廃業した会社のビルで拾ってきたガラクタじゃないですか。","ENG":"Ms. Hirose... It's not rare merchandise, but just some junk you picked up from a going-out-of-business sale.","TWN":"廣瀨……這不是什麼寶貝吧？這不是我們從倒閉的公司裡撿來的雜物嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L50_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"후후. 민서는 장사에 대해 뭘 모르네요.","JPN":"フフ、ヒミコさんは商売ってものがわからないんですね。","ENG":"Ha ha. Minseo, you don't know what you're talking about.","TWN":"呵呵，旼序你不懂怎麼做生意呢。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L1_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"자, 이 귀여운 조랑말 잠옷 보이죠?","JPN":"ほら、この可愛い子馬のパジャマを見てください。","ENG":"See these cute pony pajamas?","TWN":"你看這件可愛的迷你馬睡衣。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L2_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"이건 무려 <color=#ffd34c>마이 리틀 퍼니</color>인가에 나오는 유니콘이라고요!","JPN":"これはなんと、<color=#ffd34c>マイリトルファニー</color>とかに出てくるユニコーンなんですよ！","ENG":"The unicorn printed on them are from that famous anime, <color=#ffd34c>My Little Furries</color> or something!","TWN":"這根本就是<color=#ffd34c>彩虹小馬</color>裡的獨角獸吧！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L3_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"누가 봐도 사신상급 퀄리티를 자랑하는 짝퉁인데요…….","JPN":"どう見ても邪神像に見えるパチモンですけど……","ENG":"They obviously look fake...","TWN":"誰都看得出來這是A貨吧……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"히로세 씨, 이건 누가 봐도 재시작 해야 하는 상황이에요.","JPN":"廣瀬さん、これはどこをどうみてもリスタートするべき状況です。","ENG":"Ms. Hirose, we're lagging. We must restart.","TWN":"廣瀨，現在這個情況應該是要砍掉重練吧？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"아침부터 나와 있었는데 손님이 한 명도 없었잖아요.","JPN":"朝からやってるのに、1人も客がいなかったじゃないですか。","ENG":"We've been out here since this morning and had no customers.","TWN":"我們從早上出來到現在，根本一個客人都沒有嘛！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"안 돼요. 인생엔 뉴 게임 같은 거 없다고요. 그리고 아직 수레 대여비도 못 건졌잖아요.","JPN":"駄目です。人生にニューゲームなんかないんですよ。それに、まだ屋台のレンタル代も稼げてないし。","ENG":"No. There's no new game in life. Also, we need money to pay for this cart.","TWN":"不可以，人生是不能重來的，而且推車的租金都還沒賺回來欸。"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L10_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"하지만 너무 춥고 배고픈걸요……. 제 스태미너는 이미 0이에요…….","JPN":"でも、寒いしお腹空いたんです……ヒミコのスタミナはもう0ですよ……","ENG":"But I'm too cold and hungry... My stamina has already reached zero...","TWN":"可是我又冷又餓……我的體力值已經掉到0了……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"크흠, 바쁘겠지만 잠시 시간을 내 주겠나?","JPN":"コホン、忙しいところにすまないが、少しいいだろうか。","ENG":"Ahem. Excuse me. May I have a moment of your time?","TWN":"咳咳，不好意思打擾一下，請問你們有空嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"……네?","JPN":"……えっ？","ENG":"…Huh?","TWN":"……什麼事？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L16_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"혹시 민서랑 아는 사이에요? 둘 다 행사장에서나 볼 법한 옷차림으로 돌아다니는데요?","JPN":"もしかしてヒミコさんと知り合いですか？　2人ともイベント会場でよく見かける感じの服装ですけど。","ENG":"Are you friends with Minseo? Both of you are wearing costumes.","TWN":"請問你和旼序是認識的嗎？你們都穿著在動漫展中才會看到的服裝呢？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L17_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"히로세 씨, 아무렇지 않게 막말을 하시네요…….","JPN":"廣瀬さん、しれっとひどいこと言いますね……","ENG":"Ms. Hirose, you insult people so nonchalantly…","TWN":"廣瀨，你還真是什麼話都敢說欸……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"제 네크로노미코 의상은 디테일 하나도 놓치지 않은 걸작이라고요……. 저런 의상과 비교하지 말아 주세요…….","JPN":"ヒミコのネクロノミコの衣装は、ディテール1つ1つにこだわって作った傑作なんですよ……あんな衣装と比べないでください……","ENG":"My Necronomiko outfit is a perfect replica of the original piece... Please don't compare it to that...","TWN":"我的「亡靈之書」服裝，可是完整地呈現服裝上每個細節的傑作好嗎……不要拿它和那種服裝相提並論……"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그대가 들고 있는 잠옷, 무척이나 귀엽게 생겼군. 혹시 내게 팔 수 있겠나?","JPN":"君の持っているそのパジャマ、とても可愛らしいな。1つ欲しいのだが。","ENG":"Those pajamas in your hands. They're quite adorable. Would you sell them to me?","TWN":"你們手上的睡衣好可愛，可以賣給我嗎？"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"정말요?!","JPN":"本当ですか！？","ENG":"Really?","TWN":"你要買？！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L24_1","type":"dialog","speaker":"AKI_FREEDOM_NULL_NULL","text":{"KOREA":"물론이죠! 프리사이즈라 몸에 딱 맞으실 거예요!","JPN":"もちろんです！　フリーサイズなのでサイズも心配ありません！","ENG":"Absolutely! They're one-size-fits-all. You'll love them!","TWN":"當然可以！這是Free Size，你穿應該剛剛好！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L25_1","type":"dialog","speaker":"LEEMINSEO_FREEDOM_NULL_NULL","text":{"KOREA":"다시 보니까 정말 재현율 높은 의상이네요! 무슨 작품인지는 잘 모르겠지만요!","JPN":"改めて見ると、本当に再現度の高い衣装ですね！　何の作品かはわかりませんけど！","ENG":"On a second look, I love the costume you're wearing! For whatever title it is!","TWN":"哇，再仔細一看，你的服裝還原度很高呢！雖然我看不出來你是在扮演哪個角色！"},"stage":{"bg":"CITY_CENTER2","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":{"char_id":"AKI_FREEDOM_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"LEEMINSEO_FREEDOM_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"입어 보기 전에 정갈하게 세탁하려 했건만……. 이런 불상사가…….","JPN":"着る前に洗濯するつもりだったが……こんな予期せぬことが起こるとは……","ENG":"I wanted to wash them thoroughly before wearing them, but… how unfortunate it is...","TWN":"本來想說穿之前先洗一下的……結果竟然……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"아, 단장님. 여기 계셨네요.","JPN":"あっ、団長。ここにいたんですね。","ENG":"Ah, Captain. You're here.","TWN":"喔！團長你在這裡喔！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스 경?","JPN":"アリウス卿？","ENG":"Dame Arius?","TWN":"埃里奧斯卿?"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"잠깐……. 품에 안고 있는 그 옷은…….","JPN":"待て……君の持ってるそのパジャマは……","ENG":"Wait, those clothes in your arms...","TWN":"等一下……你抱著的衣服是……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"네. 조랑말 잠옷이에요. 방에 돌아가니까 제 잠옷들이랑 같이 있었어요.","JPN":"あっ、子馬のパジャマです。部屋に帰ったら、私のパジャマと一緒に届いてたんです。","ENG":"Yes, pony pajamas. I found them among my pajamas in my room.","TWN":"是彩虹小馬睡衣喔～我回房間後看到它和我的睡衣擺在一起。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L36_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"평기사님들이 세탁실에서 보고 제 건 줄 아셨나 봐요.","JPN":"平騎士さんたち、洗濯室でこれを見て私のだと思ったみたいです。","ENG":"The knight bachelors must have seen them in the laundry room and thought they were mine.","TWN":"應該是平民騎士在洗衣間裡看到以為是我的吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"역시…… 에리어스 경이 작고 귀엽기 때문인가?","JPN":"やはり……アリウス卿が小柄で可愛らしいからか？","ENG":"Probably... because she's so tiny and adorable, right?","TWN":"果然……是因為埃里奧斯卿嬌小又可愛嗎？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그래, 나보다는 에리어스 경과 함께하는 게 저 잠옷도 행복하겠지.","JPN":"そうだ、私よりはアリウス卿に着てもらったほうが、あのパジャマも喜ぶだろう。","ENG":"Yes, I'm sure those pajamas are better off with Dame Arius than with me.","TWN":"也是，睡衣和埃里奧斯卿在一起，會比跟我在一起幸福吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만…….","JPN":"だが……","ENG":"But...","TWN":"可是……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"하지만 이건, 조금 가슴이 아프군.","JPN":"だが、少し胸が痛む。","ENG":"But this is a little bit... heartbreaking.","TWN":"可是，怎麼覺得心有點痛痛的呢？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스 경이 단장이었다면, 저런 잠옷을 입고 다녀도 단원들의 사기가 하늘을 찔렀겠지.","JPN":"アリウス卿が団長だったら、あんなパジャマを着て出歩いても団員たちの士気は高揚したはず。","ENG":"If Dame Arius was captain, her wearing pajamas like that would never affect our men's morale.","TWN":"埃里奧斯卿如果是團長的話，團員看到她穿那種睡衣，士氣應該會衝上天吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"나도, 에리어스 경처럼 아담하고 사랑스러운 모습이었다면…….","JPN":"私もアリウス卿のように、小柄で可愛らしい見た目だったら……","ENG":"I wish I were as tiny and adorable as Dame Arius...","TWN":"如果我也長得和埃里奧斯卿一樣小巧可愛的話……"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"……장님? 단장님, 괜찮으세요?","JPN":"……ちょう？　団長、大丈夫ですか？","ENG":"…tain? Captain, are you okay?","TWN":"……團長？團長？你沒事吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"단장님 눈이 텅 비어 있어요. 아프면 제가 호- 해 드릴까요?","JPN":"目がうつろです。どこか具合が悪いなら、痛いの痛いの飛んでけーってしてあげますよ。","ENG":"Captain, your eyes look hollow all of a sudden. Are you hurt anywhere? Want me to kiss your boo-boo away?","TWN":"團長的眼神有點空洞，是哪裡不舒服嗎？要我幫你呼呼嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아, 아아. 미안하다. 잠시 잊고 있던 업무가 떠올라서.","JPN":"あ、ああ。すまない。忘れていた仕事を思い出してな。","ENG":"Ah, aah… I'm sorry. I was thinking about a task that I must complete.","TWN":"喔喔～抱歉，我只是突然想起有件事還沒做。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그래서 그 잠옷은 어떻게 할 셈인가?","JPN":"それで、そのパジャマはどうするんだ？","ENG":"So, what are you going to do with those pajamas?","TWN":"那麼剛剛那件睡衣你打算怎麼辦？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"제 잠옷은 아니니까, 원래 주인 품으로 돌아가면 좋겠어요.","JPN":"私のじゃないし、持ち主に返したいです。","ENG":"They're not mine. I want to return them to their owner.","TWN":"這又不是我的睡衣，我想把它還給原本的主人。"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"보풀도 없고 새 것처럼 뽀송뽀송하니까, 분명 조랑말을 무척 아껴 주는 분일 거예요.","JPN":"毛羽立ってもないし、新品みたいにふわふわだから、きっと子馬を大事にしている人に違いないです。","ENG":"They have no pilling and feel fluffy, like new. I bet their owner loves ponies.","TWN":"我看睡衣都還很新，也沒有起毛球，想必對方一定是很愛彩虹小馬的人吧？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L4_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스 경……!","JPN":"アリウス卿……！","ENG":"Dame Arius...!","TWN":"埃里奧斯卿……！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L5_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"어? 단장님, 제 손은 왜 꼭 잡으세요?","JPN":"え？　団長、どうして私の手を握ってるんですか？","ENG":"Erm, Captain. Why are you holding my hand?","TWN":"嗯？團長，你幹嘛抓我的手？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"물병자리의 선택은 틀리지 않았어. 그대는 생김새만 아니라 마음씨도 아름답군.","JPN":"水瓶座の目に狂いはなかった。君は見た目だけでなく、心も美しい。","ENG":"Aquarius has chosen the right patron. You're beautiful inside and outside.","TWN":"水瓶座的選擇果然沒錯！你不只長得美，心地也很美！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"한때나마 단장이란 직책에 어울리지 않게 미혹을 품었던 나를 질책해다오.","JPN":"一瞬でも心に迷いを抱き、団長に相応しくないことを考えていた私を責めてくれ。","ENG":"I deserve your reprimand, for I let my selfish desires get the best of me.","TWN":"我剛還一度掉入我並不適任團長的謊言裡！你責備我吧！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"네? 단장님은 착한 일을 많이많이 하셨는데도요?","JPN":"えっ？　団長はいいことをたくさんしたのに、ですか？","ENG":"Pardon? But Captain, you've done so many good things for others.","TWN":"為什麼？團長不是做很多很多好事嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"아니. 우리 같이 무기를 든 자들은 타인의 실수에는 너그러워도 자신의 실수에는 늘 엄격해야 한다.","JPN":"いや。私たちのように武器を手にする者は、人の過ちは許しても自分の過ちには常に厳しく向き合うべきだ。","ENG":"No. As warriors, we must be generous toward others and strict with ourselves.","TWN":"不，像我們這種手裡有武器的人，必須寬以待人，嚴以律己！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"으음~","JPN":"う～ん……","ENG":"Mm...","TWN":"嗯嗯～"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L12_1","type":"dialog","speaker":"ARIUS_ZODIAC_NULL_NULL","text":{"KOREA":"그러면 이 잠옷이 주인을 찾을 수 있게 단장님이 도와 주시면 안 될까요?","JPN":"じゃあ、このパジャマが持ち主の元に帰られるように、団長手伝ってくれませんか？","ENG":"Then, Captain, could you help me return these pajamas to their owner?","TWN":"那團長可以幫我找到睡衣的主人嗎？"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ARIUS_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"……바라던 바다.","JPN":"……望むところだ。","ENG":"...I thought you'd never ask.","TWN":"……正如我所願！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"기사의 명예를 걸고 반드시 주인에게 데려다 주지.","JPN":"騎士の名にかけて、必ず持ち主の元に帰してあげよう。","ENG":"I swear on my knightly honor that I will bring them to their owner.","TWN":"我以騎士的榮譽宣告，我一定會把睡衣帶回主人身邊的！"},"stage":{"bg":"CORRIDOR_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그런 일이 있었다고 에리어스 경에게 들었습니다만…….","JPN":"……ということがあったと、アリウス卿から聞いていますが。","ENG":"That's what Dame Arius said happened.","TWN":"我是有聽埃里奧斯卿提起這件事……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"업무 정리도 부단장으로서 해야 할 일입니다. 경과를 들려 주시겠습니까, 단장님?","JPN":"仕事の状況確認も、副団長の責務です。進捗をお聞きしてもいいでしょうか、団長。","ENG":"Task organization is part of my duties as deputy captain. Could you tell me how it went, Captain?","TWN":"整理業務也是副團長的職責之一。團長，你可以跟我說事情發生的經過嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"크흠. 오, 오늘은 차가 평소보다 조금 뜨겁군.","JPN":"コホン。きょ、今日はお茶がいつもより少し熱いな。","ENG":"Ahem! M-my tea is hotter than usual.","TWN":"咳咳，今天的茶好像比平常燙呢。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"에리어스 경과 약속한 대로 주인은 찾았어.","JPN":"アリウス卿と約束したとおり、持ち主を探し出して返した。","ENG":"It's just as I promised to Dame Arius. I brought them to their owner.","TWN":"我已經依照和埃里奧斯卿的約定找到了主人。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L23_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그렇지만 괜한 분란을 일으키지 않게 신변에 대해선 비밀로 부치고 싶군.","JPN":"だが、余計なことが起こらぬように、その人の正体は秘密にしてやりたい。","ENG":"But I don't want to stir up a scandal. I should keep her identity secret.","TWN":"不過，避免不必要的騷動，關於那個人的身分，我想要保密。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L24_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"…….","TWN":"……"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"PIONE_ZODIAC_NULL_NULL","text":{"KOREA":"그렇다면 그 주인에게 전해 주십시오. 사적인 용도로만 사용한다면 저도 단속하지 않는다고 말입니다.","JPN":"それなら、その人に伝えてください。私的に使うだけなら、私も何も言うつもりはないと。","ENG":"Then, please tell her that I won't intervene so long as she uses them in private.","TWN":"那請團長轉告那個人，若是作為私人的用途，我是不會特別管教的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L26_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"정말인가?","JPN":"本当か？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"PIONE_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L28_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"부단장에게서 새로운 융통성을 찾게 되어 기쁘군.","JPN":"副団長がそんなに融通の効く人だったとは、嬉しい発見だ。","ENG":"Deputy, I'm happy for your newfound flexibility.","TWN":"我很高興看到副團長變得如此通情達理。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_ZODIAC_NULL_NULL","text":{"KOREA":"그 말, 확실하게 전해 두도록 하지.","JPN":"その言葉、確かに伝えるとしよう。","ENG":"I'll make sure she knows.","TWN":"我會如實轉告的。"},"stage":{"bg":"ROOM_02","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ESTAROSSA_ZODIAC_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};